Replace string interpolation with parameterized queries using sqlite3's placeholder API:

const query = 'SELECT * FROM users WHERE username = ? AND password = ?';
db.get(query, [username, password], (err, row) => { ... });

Load seed credentials from environment variables and use a strong hashed password:

const bcrypt = require('bcrypt');
const adminPass = process.env.ADMIN_PASSWORD;
const hash = bcrypt.hashSync(adminPass, 12);
db.run('INSERT INTO users VALUES (1, ?, ?)', ['admin', hash]);

Hash passwords with bcrypt before storing, and compare using bcrypt:

const bcrypt = require('bcrypt');
// On registration:
const hash = await bcrypt.hash(password, 12);
db.run('INSERT INTO users VALUES (?, ?, ?)', [id, username, hash]);
// On login:
db.get('SELECT * FROM users WHERE username = ?', [username], async (err, row) => {
  if (row && await bcrypt.compare(password, row.password)) { res.send('Login successful!'); }
});

